import React from 'react'
import './FoodLog.css';
import { createRoot } from 'react-dom/client';
var numberofMeals = 0;
const socket = new WebSocket('ws://localhost:8080');
socket.binaryType = "arraybuffer"; 
let logRoot;

socket.addEventListener('open', event =>{
    console.log("Socket connection open.")
});

socket.addEventListener('message', event => {
  var searchResults
  console.log('Message from server: ', event.data);
  if(event.data.slice(0,"SEARCH_RESULTS:".length)=="SEARCH_RESULTS:"){
    searchResults = JSON.parse(event.data.slice("SEARCH_RESULTS:".length,event.data.length));
    console.log(searchResults);
  };
  
});

socket.addEventListener("open", (event) => {
  socket.send("Food_name=Strawberries");
  console.log("Message sent to server: Food_name=Strawberries")
});


function Meal(props){
  return(
      <div id={props.name} className='meal'>
        <h1>
          {props.name}
        </h1>
        <ul>
          <li>1</li>
          <li>2</li>
          <li>3</li>
        </ul>
      </div>
  )
}


const FoodLog = () => {
  var mealName;
  var logRoot;
  function MealAdd() {
    if(!logRoot){
      console.log("Creating subroot");
      logRoot = createRoot(document.getElementById('meals'));
    };
    logRoot.render(<Meal name={mealName}/>); 
  }

  return (
    <main className='FoodLog'>
        <h2>Food Log</h2>
        <p style={{ marginTop: '1rem' }}>
          This is the food log page.<br/><br/>
        </p>
        <input name="mealName" placeholder='Meal name' onChange={e => {mealName = e.target.value;console.log("mealName ="+mealName);}}/>
        <button name="mealAddButton" onClick={MealAdd}>Add meal</button>
        <div id='meals'></div>
    </main>
  )
}








export default FoodLog
